    "steps": [
      {
        "order": 1,
        "instruction": "草鱼（一般 3 斤 ）从背部切开，两面沿着鱼的背部往下划几刀，不要划到鱼肚皮，不然不易定型",
        "duration": null,
        "tip": "可以用热水浇在鱼身上洗去粘液或者用刷子在流动水龙头下面不停的刷洗，直到摸着没有黏糊糊的手感。"
      },
      {
        "order": 2,
        "instruction": "把鱼放到容器中，加入料酒，10g 白胡椒粉，5g 食盐抹匀腌制二十分钟入味。",
        "duration": null,
        "tip": null
      },
      {
        "order": 3,
        "instruction": "把半根大葱切成一块一块，大蒜粒中间切开，和八角香叶桂皮放在一个容器中",
        "duration": null,
        "tip": null
      },
      {
        "order": 4,
        "instruction": "干辣椒段中间一分为二切开并和灯笼椒装在一个容器中",
        "duration": null,
        "tip": null
      },
      {
        "order": 5,
        "instruction": "芹菜切小段",
        "duration": null,
        "tip": null
      },
      {
        "order": 6,
        "instruction": "豆芽焯水",
        "duration": null,
        "tip": null
      },
      {
        "order": 7,
        "instruction": "千张焯水切成丝",
        "duration": null,
        "tip": null
      },
      {
        "order": 8,
        "instruction": "洋葱切成丝。",
        "duration": null,
        "tip": null
      },
      {
        "order": 9,
        "instruction": "烤制鱼",
        "duration": null,
        "tip": "家里有烤箱的可以在烤盘刷上底油，鱼皮朝下，直到烤制两面金黄，然后撒上孜然粉"
      },
      {
        "order": 10,
        "instruction": "锅中撒上 20ml 食用油，等到油热后，把大葱大蒜八角香叶倒入炒香",
        "duration": null,
        "tip": null
      },
      {
        "order": 11,
        "instruction": "加上一包火锅底料的一半和 15-20g 豆瓣酱，炒出红油",
        "duration": null,
        "tip": null
      },
      {
        "order": 12,
        "instruction": "加入 5g 白糖，10g 食盐，5ml 生抽调味，倒入和食材齐平的清水煮开",
        "duration": null,
        "tip": null
      },
      {
        "order": 13,
        "instruction": "依次下入芹菜段，豆芽，千张丝，不用煮熟，稍微烫一下后铺上洋葱丝，放上烤鱼",
        "duration": null,
        "tip": null
      },
      {
        "order": 14,
        "instruction": "加入干辣椒，灯笼椒，青花椒",
        "duration": null,
        "tip": null
      },
      {
        "order": 15,
        "instruction": "另一个锅烧油，油热后浇在刚加入的辣椒上面激发出香味",
        "duration": null,
        "tip": null
      },
      {
        "order": 16,
        "instruction": "最后撒上熟花生米，葱花，白芝麻，香菜",
        "duration": null,
        "tip": null
      },
      {
        "order": 17,
        "instruction": "煮 5-6 分钟，美味即成。",
        "duration": null,
        "tip": null
      }
    ],
