    "steps": [
      {
        "order": 1,
        "instruction": "老姜切丝,小葱不用切。",
        "duration": null,
        "tip": null
      },
      {
        "order": 2,
        "instruction": "根据计算公式倒入料酒、清水。",
        "duration": null,
        "tip": null
      },
      {
        "order": 3,
        "instruction": "用手捏揉 5 分钟，使姜葱的味道充分溶解在水中。",
        "duration": null,
        "tip": null
      },
      {
        "order": 4,
        "instruction": "将猪肉去皮洗净",
        "duration": null,
        "tip": null
      },
      {
        "order": 5,
        "instruction": "切成长度 8~10 厘米，厚度 1.5 厘米的肉条。",
        "duration": null,
        "tip": null
      },
      {
        "order": 6,
        "instruction": "根据上面的计算公式加入盐，十三香、胡椒粉、味精、鸡精、花椒碎、花椒粒、生抽。",
        "duration": null,
        "tip": null
      },
      {
        "order": 7,
        "instruction": "倒入前面制作好的葱姜水",
        "duration": null,
        "tip": null
      },
      {
        "order": 8,
        "instruction": "抓匀并且充分揉制 10 分钟，直至肉吸收所有水分并且变得粘手。",
        "duration": null,
        "tip": null
      },
      {
        "order": 9,
        "instruction": "封上保鲜膜放冷藏室静置 30 分钟。",
        "duration": null,
        "tip": null
      },
      {
        "order": 10,
        "instruction": "将面粉、红薯粉倒入腌制好的肉中，加入鸡蛋清。",
        "duration": null,
        "tip": null
      },
      {
        "order": 11,
        "instruction": "充分揉制 15 分钟。",
        "duration": null,
        "tip": null
      },
      {
        "order": 12,
        "instruction": "锅中倒入植物油，根据锅大小控制油量，油面高度 3 厘米以上。",
        "duration": null,
        "tip": null
      },
      {
        "order": 13,
        "instruction": "大火将温加热至 150° 后，转小火保持温度。",
        "duration": null,
        "tip": null
      },
      {
        "order": 14,
        "instruction": "将裹好粉的肉条用筷子夹入油锅中，捋成自己喜欢的形状，炸 3~5 分钟定型。目测颜色微黄，用锅铲翻动感受倒略微有些硬了就可以。具体时间受肉块大小、油温、裹粉程度影响。",
        "duration": null,
        "tip": null
      },
      {
        "order": 15,
        "instruction": "捞出沥油。",
        "duration": null,
        "tip": null
      },
      {
        "order": 16,
        "instruction": "将油温升至 180° 放入初炸好的肉条，炸至金黄色即可捞出。",
        "duration": null,
        "tip": null
      }
    ],
