    "steps": [
      {
        "order": 1,
        "instruction": "瘦肉切块（每块 2-3 cm ），放入大碗中，加入鸡蛋 1 个 、生粉 50 g 、生抽 3 ml 、鸡精 2 g",
        "duration": null,
        "tip": null
      },
      {
        "order": 2,
        "instruction": "充分搅拌,直至生粉包裹住瘦肉块（太稀则继续加生粉，太干则加水），然后加入 5 ml 油，在充分搅拌后备用",
        "duration": null,
        "tip": null
      },
      {
        "order": 3,
        "instruction": "在准备一个碗，加入番茄酱、鸡精 3 g 、生抽 2 ml 、姜末、白砂糖、生粉 10 g \\香醋、凉水 200 ml ,充分搅拌后备用",
        "duration": null,
        "tip": null
      },
      {
        "order": 4,
        "instruction": "切一个凤梨, 准备 6 个 （每个 1.5-2 cm）凤梨块",
        "duration": null,
        "tip": null
      },
      {
        "order": 5,
        "instruction": "起锅烧油，倒入 500 ml 油，一直烧油直到听到油炸声",
        "duration": null,
        "tip": null
      },
      {
        "order": 6,
        "instruction": "将瘦肉一个一个放入锅中（切记不可以整碗倒入），保证每个肉不要粘在一起",
        "duration": null,
        "tip": null
      },
      {
        "order": 7,
        "instruction": "全部放入瘦肉后，每 30 S 用勺子来回两面翻转瘦肉块，直至瘦肉块表面金黄",
        "duration": null,
        "tip": null
      },
      {
        "order": 8,
        "instruction": "取出瘦肉，一分钟后倒入油锅中继续炸，直至瘦肉块表面出现焦黄后，取出放入大碗备用",
        "duration": null,
        "tip": null
      },
      {
        "order": 9,
        "instruction": "起锅，倒入汤汁，30 S 后倒入瘦肉块、凤梨块，充分翻炒后 出锅",
        "duration": null,
        "tip": null
      },
      {
        "order": 10,
        "instruction": "摆上芝麻",
        "duration": null,
        "tip": null
      }
    ],
    "prepTime": 30,
    "cookTime": 40,
    "difficulty": 4,
    "tasteRating": 3.8,
    "nutrition": {
      "calories": 681,
      "protein": 60,
      "carbs": 26,
      "fat": 38,
      "fiber": 5
    },
    "servings": 2,
    "equipment": [
      "炒锅",
      "菜刀",
      "砧板"
    ],
    "tags": [
      "高热量"
    ],
    "tips": [
      "更多情况下，福州当地会选用马蹄（解腻）和马铃薯（洗油），因为疫情期间买不到，所以选用了凤梨",
      "闽菜以甜为主，如果吃不惯的可以放弃白糖",
      "可以通过勺子敲打瘦肉块，听到声响来判断是否炸透瘦肉"
    ]
