    "steps": [
      {
        "order": 1,
        "instruction": "小葱切碎（葱白和葱叶分开）、蒜瓣拍碎，丢案板上备用。",
        "duration": null,
        "tip": null
      },
      {
        "order": 2,
        "instruction": "打碎鸡蛋，捞一点蛋清到一只碗中，剩下的丢入另一只碗中备用。",
        "duration": null,
        "tip": null
      },
      {
        "order": 3,
        "instruction": "将绿豆芽放入锅中，大火煮 60 秒。豆芽捞出，过凉水，放入盘中备用。",
        "duration": null,
        "tip": null
      },
      {
        "order": 4,
        "instruction": "黄瓜切丝放入盘中备用，可和豆芽丢一起。",
        "duration": null,
        "tip": null
      },
      {
        "order": 5,
        "instruction": "处理面筋，单独丢一个盘中。",
        "duration": null,
        "tip": null
      },
      {
        "order": 6,
        "instruction": "肉切细条状，加入淀粉与刚刚碗中的鸡蛋清、胡椒粉，顺时针拌匀。",
        "duration": null,
        "tip": null
      },
      {
        "order": 7,
        "instruction": "注：超市购买来的凉皮表面一般会有食用油，可以使用自来水清洗。面筋同样。",
        "duration": null,
        "tip": null
      },
      {
        "order": 8,
        "instruction": "注：清洗面筋之后，请用手将面筋中的大量水分挤出（不需过于用力）。",
        "duration": null,
        "tip": null
      },
      {
        "order": 9,
        "instruction": "加入食用油，锅热倒出。",
        "duration": null,
        "tip": null
      },
      {
        "order": 10,
        "instruction": "倒入处理好的肉，翻炒均匀至变色，倒入碗中备用。",
        "duration": null,
        "tip": null
      },
      {
        "order": 11,
        "instruction": "趁锅热，加入 20g 食用油（高血压人群可降低用量），倒入葱白、蒜爆炒出香。",
        "duration": null,
        "tip": null
      },
      {
        "order": 12,
        "instruction": "加入河粉，淋入老抽提色，翻炒均匀后再加入河粉炒料，继续翻炒。",
        "duration": null,
        "tip": null
      },
      {
        "order": 13,
        "instruction": "河粉即将透明时，放入炒制好的肉丝与面筋，并加入生抽提鲜，简单翻炒两次。",
        "duration": null,
        "tip": null
      },
      {
        "order": 14,
        "instruction": "加入豆芽与黄瓜丝，翻炒至河粉完全透明。",
        "duration": null,
        "tip": null
      },
      {
        "order": 15,
        "instruction": "关火！",
        "duration": null,
        "tip": null
      },
      {
        "order": 16,
        "instruction": "撒入葱叶点缀，把锅端起。",
        "duration": null,
        "tip": null
      },
      {
        "order": 17,
        "instruction": "倒入盘中，开始干饭。",
        "duration": null,
        "tip": null
      }
    ],
