    "steps": [
      {
        "order": 1,
        "instruction": "将馒头切成小块或小片。",
        "duration": null,
        "tip": null
      },
      {
        "order": 2,
        "instruction": "选有鸡蛋的话将鸡蛋打进碗里，打散（可加盐和五香粉各 1g 或不加，等炒的过程中加）。",
        "duration": null,
        "tip": null
      },
      {
        "order": 3,
        "instruction": "鸡蛋浇在馒头上，拌匀，鸡蛋不宜过多。",
        "duration": null,
        "tip": null
      },
      {
        "order": 4,
        "instruction": "大火热锅，倒入食用油（不锈钢锅怕伤锅的话可以先倒油，烧至油热也可也可）",
        "duration": null,
        "tip": null
      },
      {
        "order": 5,
        "instruction": "将馍丁放进去翻炒，翻炒均匀。",
        "duration": null,
        "tip": null
      },
      {
        "order": 6,
        "instruction": "将火调小，炒至馍丁呈金黄色。",
        "duration": null,
        "tip": null
      },
      {
        "order": 7,
        "instruction": "放入盐，胡椒粉，五香粉。",
        "duration": null,
        "tip": null
      },
      {
        "order": 8,
        "instruction": "最后将葱花放入一起翻炒几下。",
        "duration": null,
        "tip": null
      },
      {
        "order": 9,
        "instruction": "关火出锅。",
        "duration": null,
        "tip": null
      }
    ],
