    "steps": [
      {
        "order": 1,
        "instruction": "取一只鸡腿，鸡皮朝下放在砧板上",
        "duration": null,
        "tip": null
      },
      {
        "order": 2,
        "instruction": "用刀尖沿着鸡腿骨头的轮廓轻轻划开，从一端到另一端",
        "duration": null,
        "tip": null
      },
      {
        "order": 3,
        "instruction": "用手指或刀背慢慢推开鸡肉，让骨头暴露出来。如果遇到筋膜，用刀尖切断",
        "duration": null,
        "tip": null
      },
      {
        "order": 4,
        "instruction": "当鸡肉完全分离后，握住骨头一端，轻轻扭转并拔出",
        "duration": null,
        "tip": null
      },
      {
        "order": 5,
        "instruction": "重复上述步骤将所有鸡腿去骨",
        "duration": null,
        "tip": null
      },
      {
        "order": 6,
        "instruction": "去骨鸡腿加入黑胡椒粉、黑胡椒碎、盐、姜片腌制 5 分钟",
        "duration": null,
        "tip": null
      },
      {
        "order": 7,
        "instruction": "碗里加入料酒、生抽、蜂蜜、老抽清水拌匀",
        "duration": null,
        "tip": null
      },
      {
        "order": 8,
        "instruction": "蔬菜焯水 1-2 分钟煮熟捞起",
        "duration": null,
        "tip": null
      },
      {
        "order": 9,
        "instruction": "热锅放油 15 ml 放入拍碎的大蒜爆香",
        "duration": null,
        "tip": null
      },
      {
        "order": 10,
        "instruction": "放入鸡腿中小火煎至两面金黄，如果感觉锅中太干，补 5-10 ml 油",
        "duration": null,
        "tip": null
      },
      {
        "order": 11,
        "instruction": "加入调好的酱汁，盖好盖子中小火（在燃气灶上使用小火）焖 5-10 分钟熟透，酱汁浓稠起泡即可",
        "duration": null,
        "tip": null
      },
      {
        "order": 12,
        "instruction": "切件，和蔬菜一起摆在饭面，淋入煎鸡腿的酱汁就可以慢慢享用啦",
        "duration": null,
        "tip": null
      }
    ],
    "prepTime": 30,
    "cookTime": 40,
    "difficulty": 4,
    "tasteRating": 3.8,
    "nutrition": {
      "calories": 1670,
      "protein": 63,
      "carbs": 271,
      "fat": 37,
      "fiber": 5
    },
    "servings": 2,
    "equipment": [
      "炒锅",
      "菜刀",
      "砧板"
    ],
    "tags": [
      "高热量",
      "下饭菜"
    ],
    "tips": [
      "如果使用白砂糖、淀粉组合代替一定让白砂糖和淀粉完全溶解再下锅，否则容易糊锅",
      "焖煮时每隔 3-5 分钟翻搅一下，避免局部过热",
      "如果酱汁冒大泡、颜色变深褐，或边缘出现细密焦糖结晶，立即关火",
      "参考资料：[【照烧鸡腿饭的做法步骤图，照烧鸡腿饭怎么做好吃】小晓姐姐_下厨房](https://www.xiachufang.com/recipe/104126605/)"
    ]
